import { AsyncLocalStorage } from "async_hooks";

type Store = {
  requestId?: string | null;
  logger?: any;
};

export const asyncLocalStorage = new AsyncLocalStorage<Store>();

export function getRequestContext(): Store | undefined {
  return asyncLocalStorage.getStore();
}

import { Request, Response, NextFunction } from 'express';
import { ApiResponse, ApiError } from './http.js';

export function ok<T = any>(data?: T): ApiResponse<T> {
  return { success: true, data };
}

export function fail(code: string, message: string, details?: any): ApiError {
  return { code, message, details };
}

export function wrap(
  handler: (req: Request, res: Response, next: NextFunction) => Promise<any> | any
) {
  return async function (req: Request, res: Response, next: NextFunction) {
    try {
      const result = await handler(req, res, next);
      if (!res.headersSent) {
        // If handler already returned a normalized ApiResponse, send it as-is
        if (result && typeof result === 'object' && 'success' in result) {
          const r = result as ApiResponse;
          if (!r.success && r.error?.code) {
            res.status(httpStatusFromCode(r.error.code)).json(r);
          } else {
            res.json(r);
          }
        } else {
          res.json(ok(result));
        }
      }
    } catch (err) {
      // If handler threw an ApiError-like object, normalize and send
      const maybeApiError = err as ApiError;
      if (maybeApiError && typeof maybeApiError.code === 'string') {
        const status = httpStatusFromCode(maybeApiError.code);
        if (!res.headersSent) res.status(status).json({ success: false, error: maybeApiError });
        return;
      }
      next(err);
    }
  };
}

function httpStatusFromCode(code: string): number {
  switch (code) {
    case 'NOT_FOUND':
      return 404;
    case 'UNAUTHORIZED':
      return 401;
    case 'FORBIDDEN':
      return 403;
    case 'CONFLICT':
      return 409;
    case 'INVALID_INPUT':
    case 'VALIDATION_ERROR':
      return 400;
    case 'INTERNAL_ERROR':
    default:
      return 500;
  }
}

export type ApiError = {
  code: string;
  message: string;
  details?: any;
};

export type ApiResponse<T = any> = {
  success: boolean;
  data?: T;
  error?: ApiError;
};

export function successResponse<T = any>(data?: T): ApiResponse<T> {
  return { success: true, data };
}

export function errorResponse(code: string, message: string, details?: any): ApiResponse {
  return { success: false, error: { code, message, details } };
}

export function isApiError(e: any): e is ApiError {
  return e && typeof e === 'object' && typeof e.code === 'string' && typeof e.message === 'string';
}

