      return { terminal_id: terminal.id, branchId: terminal.branchId };
    } catch (err: any) {
      if (err.message === 'Branch not found') throw fail('NOT_FOUND', err.message);
      if (err.message === 'Terminal has already been registered') throw fail('CONFLICT', err.message);
      throw fail('INTERNAL_ERROR', err.message || 'Failed to register terminal');
    }
  });

  static login = wrap(async (req: Request) => {
    const { terminal_token } = req.body;

    if (!terminal_token) throw fail('INVALID_INPUT', 'terminal_token is required');

    try {
      const terminal = await TerminalService.loginTerminal(terminal_token);
      return { terminal_id: terminal.id, branchId: terminal.branchId };
    } catch (err: any) {
      throw fail('UNAUTHORIZED', err.message || 'Failed to login terminal');
    }
  });

  static acknowledgeOrder = wrap(async (req: Request) => {
    const { order_id } = req.params;
    const terminal_id = req.user?.id as string;

    const order = await TerminalService.acknowledgeOrder(order_id, terminal_id);
    return order;
  });

  static assignOrder = wrap(async (req: Request) => {
    const { order_id } = req.params;
    const terminal_id = req.user?.id as string;

    await TerminalService.assignOrder(order_id, terminal_id);
    return { status: 'assigned' };
  });

  static acceptOrder = wrap(async (req: Request) => {
    const { order_id } = req.params;
    const terminal_id = req.user?.id as string;

    const order = await TerminalService.acceptOrder(order_id, terminal_id);
    return order;
  });

  static rejectOrder = wrap(async (req: Request) => {
    const { order_id } = req.params;
    const terminal_id = req.user?.id as string;

    const order = await TerminalService.rejectOrder(order_id, terminal_id);
    return order;
  });

  static heartbeat = wrap(async (req: Request) => {
    const terminal_id = req.user?.id as string;
    await TerminalService.updateHeartbeat(terminal_id);
    return { status: 'ok' };
  });

  static ordersStream = wrap(async () => {
    throw fail('NOT_IMPLEMENTED', 'Not implemented');
  });
}

﻿import { Server, Socket } from "socket.io";
import { prisma } from "../prisma/client.ts";
import { TerminalService } from "../services/terminal/terminal.service.ts";
import logger from "../logger.ts";

export function registerTerminalEvents(io: Server, socket: Socket) {
  socket.on("terminal_connected", async () => {
    const terminalToken = socket.handshake.auth?.terminal_token;

    if (!terminalToken) {
      logger.warn("Terminal socket connection failed: no terminal_token");
      socket.disconnect();
      return;
    }

    try {
      const terminal = await TerminalService.loginTerminal(terminalToken);
      socket.data.terminal_id = terminal.id;
      socket.data.branch_id = terminal.branchId;
      socket.join(`terminal_${terminal.id}`);
      socket.join(`branch_${terminal.branchId}`);

      const { getIO } = await import("../lib/socket.ts");
      getIO().to("admin_dashboard").emit("terminal_online", {
        terminal_id: terminal.id,
        isOnline: true,
        lastSeen: new Date(),
      });
    } catch (err: any) {
      logger.warn({ err }, "Terminal socket connection failed");
      socket.disconnect();
    }
  });

  socket.on("printer_status", async (data: any) => {
    try {
      const status = data?.status ?? "offline";
      const payload = {
        terminal_id: socket.data.terminal_id,
        branch_id: socket.data.branch_id,
        status,
        queue_length: data?.queue_length ?? 0,
        timestamp: data?.timestamp ? new Date(data.timestamp) : new Date(),
      };
      io.to("admin_dashboard").emit("printer_status_update", payload);
    } catch (err: any) {
      logger.error({ err }, "Error forwarding printer status");
    }
  });

  socket.on("disconnect", async () => {
    try {
      if (socket.data.terminal_id) {
        await prisma.terminal.update({
          where: { id: socket.data.terminal_id },
          data: {
            isOnline: false,
            lastSeen: new Date(),
          },
        });

        io.to("admin_dashboard").emit("terminal_offline", {
          terminal_id: socket.data.terminal_id,
          isOnline: false,
          lastSeen: new Date(),
        });
      }
    } catch (err: any) {
      logger.error({ err }, "Error updating terminal offline status");
    }
  });
}

