      result.services.redis = "disabled";
    }
  } catch (e) {
    result.services.redis = "down";
    logger.warn({ err: e }, "Readiness: Redis not ready");
  }

  try {
    result.services.workers = workersInitialized ? "up" : "initializing";
  } catch (e) {
    result.services.workers = "down";
