﻿import { prisma } from "../../prisma/client.ts";
import { cacheDashboardMetrics, getDashboardMetrics } from "../../lib/redis.ts";

export class AdminDashboardService {
  static async getMetrics(branchId: string) {
    const cachedMetrics = await getDashboardMetrics(branchId);
    if (cachedMetrics) {
      return cachedMetrics;
    }

    const now = new Date();
    const startOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    const orderFilter = { status: "delivered", branchId };

    const [salesAgg, totalOrders, todayAgg, activeCouriers, activeCustomers, topSellingItems] = await Promise.all([
      prisma.orderItem.aggregate({ _sum: { price: true }, where: { order: orderFilter } }),
      prisma.order.count({ where: orderFilter }),
      prisma.orderItem.aggregate({ _sum: { price: true }, where: { order: { ...orderFilter, createdAt: { gte: startOfDay } } } }),
      prisma.courier.count({ where: { active: true, branchId } }),
      prisma.customer.count({ where: { orders: { some: { branchId, createdAt: { gte: startOfMonth } } } } }),
      prisma.orderItem.groupBy({
        by: ["itemId"],
        _sum: { quantity: true },
        where: { order: { branchId } },
        orderBy: { _sum: { quantity: "desc" } },
        take: 10
      })
    ]);

    const itemIds = topSellingItems.map((item) => item.itemId);
    const items = await prisma.menuItem.findMany({
      where: { id: { in: itemIds } },
      select: { id: true, name: true }
    });

    const topItems = topSellingItems.map((item) => ({
      itemId: item.itemId,
      quantity: item._sum.quantity,
      item: items.find((i) => i.id === item.itemId) || null
    }));

    const metrics = {
      totalSales: salesAgg._sum.price || 0,
      totalOrders,
      todaySales: todayAgg._sum.price || 0,
      activeCouriers,
      activeCustomers,
      topSellingItems: topItems
    };

    await cacheDashboardMetrics(branchId, metrics, 5);
    return metrics;
  }

  static async getSalesChart(period: "daily" | "weekly" | "monthly", branchId: string) {
    const data = [];
    for (let i = 0; i < 30; i++) {
      const date = new Date();
      date.setDate(date.getDate() - i);
      data.push({
        date: date.toISOString().split('T')[0],
        sales: Math.floor(Math.random() * 1000) + 100
      });
    }
    return data.reverse();
  }

  static async getOrderChart(period: "daily" | "weekly" | "monthly", branchId: string) {
    const data = [];
    for (let i = 0; i < 30; i++) {
      const date = new Date();
      date.setDate(date.getDate() - i);
      data.push({
        date: date.toISOString().split('T')[0],
        orders: Math.floor(Math.random() * 50) + 10
      });
    }
    return data.reverse();
  }

  static async emitMetricsUpdate(branchId: string) {
    const { getAdminNamespace } = await import("../../socket/index.ts");
    const metrics = await this.getMetrics(branchId);

    const eventData = {
      success: true,
      event: "admin:metrics_update",
      data: metrics
    };

    getAdminNamespace().to(`branch_${branchId}`).emit("admin:metrics_update", eventData);
  }

  static async emitOrderUpdate(order: any) {
    const { getAdminNamespace } = await import("../../socket/index.ts");

    const eventData = {
      success: true,
      event: "admin:order_update",
      data: {
        orderId: order.id,
        status: order.status,
        customerId: order.customerId,
        createdAt: order.createdAt
      }
    };

    getAdminNamespace().to(`branch_${order.branchId}`).emit("admin:order_update", eventData);
    this.emitMetricsUpdate(order.branchId);
  }

  static async emitCourierUpdate(courier: any) {
    const { getAdminNamespace } = await import("../../socket/index.ts");

    const eventData = {
      success: true,
      event: "admin:courier_update",
      data: {
        courierId: courier.id,
        name: courier.name,
        active: courier.active,
        location: courier.location
      }
    };

    getAdminNamespace().to(`branch_${courier.branchId}`).emit("admin:courier_update", eventData);
    this.emitMetricsUpdate(courier.branchId);
  }
}

﻿import { prisma } from "../../prisma/client.ts";
import { OrderLifecycleService } from "../order/orderLifecycle.service.ts";

export class AdminOrdersService {
  static async getAll(branchId: string, filters: {
    status?: string;
    customerId?: string;
    startDate?: Date;
    endDate?: Date;
    page?: number;
    limit?: number;
  }) {
    const { status, customerId, startDate, endDate, page = 1, limit = 20 } = filters;

    const where: any = { branchId };
    if (status) where.status = status;
    if (customerId) where.customerId = customerId;
    if (startDate || endDate) {
      where.createdAt = {};
      if (startDate) where.createdAt.gte = startDate;
      if (endDate) where.createdAt.lte = endDate;
    }

    const orders = await prisma.order.findMany({
      where,
      include: {
        customer: true,
        items: {
          include: {
            item: true
          }
        }
      },
      orderBy: { createdAt: "desc" },
      skip: (page - 1) * limit,
      take: limit
    });

    const total = await prisma.order.count({ where });

    return { orders, total, page, limit };
  }

  static async getById(orderId: string, branchId: string) {
    return prisma.order.findFirst({
      where: { id: orderId, branchId },
      include: {
        customer: true,
        items: {
          include: {
            item: true
          }
        }
      }
    });
  }

  static async updateStatus(orderId: string, branchId: string, status: string, estimatedTime?: number) {
    const order = await prisma.order.findFirst({ where: { id: orderId, branchId } });
    if (!order) throw new Error("Order not found for branch");

    const updated = await OrderLifecycleService.updateStatus(
      orderId,
      status,
      estimatedTime ? new Date(Date.now() + estimatedTime * 60000) : undefined
    );

    return prisma.order.findUnique({
      where: { id: orderId },
      include: {
        customer: true
      }
    });
  }

  static async assignCourier(orderId: string, branchId: string, courierToken: string) {
    const order = await prisma.order.findFirst({ where: { id: orderId, branchId } });
    if (!order) throw new Error("Order not found for branch");

    await OrderLifecycleService.setCourierToken(orderId, courierToken, new Date(Date.now() + 1000 * 60 * 60 * 3));

    return prisma.order.findUnique({ where: { id: orderId }, include: { customer: true } });
