import { Socket } from "socket.io";

interface ConnectionLimitConfig {
  maxPerIP: number;       // max connections per IP
  perNamespace?: {
    [key: string]: number;
  };
}

interface ConnectionState {
  namespace: string;
  socketCount: number;
  sockets: Set<string>;
}

// ===== GLOBAL STATE =====
const ipConnections = new Map<string, Set<string>>();  // IP -> socket IDs
const namespaceConnections = new Map<string, ConnectionState>();  // namespace -> connection state

const DEFAULT_CONFIG: ConnectionLimitConfig = {
  maxPerIP: 5,
  perNamespace: {
    "/orders": 10,
    "/couriers": 5,
    "/admin": 20,
    "/kds": 10,
    "/customer": 5
  }
};

/**
 * Check if a new connection is allowed
 */
export const canConnect = (
  socket: Socket,
  config: ConnectionLimitConfig = DEFAULT_CONFIG
): { allowed: boolean; reason?: string } => {
  const clientIP = socket.handshake.address;
  const namespace = socket.nsp.name;
  
  // ===== CHECK IP-LEVEL LIMIT =====
  if (!ipConnections.has(clientIP)) {
    ipConnections.set(clientIP, new Set());
  }
  
  const ipSockets = ipConnections.get(clientIP)!;
  
  if (ipSockets.size >= config.maxPerIP) {
    return {
      allowed: false,
      reason: `IP ${clientIP} has reached max connections (${config.maxPerIP})`
    };
  }

  // ===== CHECK NAMESPACE-LEVEL LIMIT =====
  const namespaceLimit = config.perNamespace?.[namespace] || config.maxPerIP;
  
  if (!namespaceConnections.has(namespace)) {
    namespaceConnections.set(namespace, {
      namespace,
      socketCount: 0,
      sockets: new Set()
    });
  }

  const nsState = namespaceConnections.get(namespace)!;
  
  if (nsState.socketCount >= namespaceLimit) {
    return {
      allowed: false,
      reason: `Namespace ${namespace} has reached max connections (${namespaceLimit})`
    };
  }

  // ===== CONNECTION ALLOWED =====
  ipSockets.add(socket.id);
  nsState.sockets.add(socket.id);
  nsState.socketCount++;

  return { allowed: true };
};

/**
 * Register a successful connection
 */
export const registerConnection = (socket: Socket): void => {
  const clientIP = socket.handshake.address;
  const namespace = socket.nsp.name;

  if (!ipConnections.has(clientIP)) {
    ipConnections.set(clientIP, new Set());
  }
  ipConnections.get(clientIP)!.add(socket.id);

  if (!namespaceConnections.has(namespace)) {
    namespaceConnections.set(namespace, {
      namespace,
      socketCount: 0,
      sockets: new Set()
    });
  }

  const nsState = namespaceConnections.get(namespace)!;
  nsState.sockets.add(socket.id);
  nsState.socketCount++;
};

/**
 * Clean up connection when socket disconnects
 */
export const unregisterConnection = (socket: Socket): void => {
  const clientIP = socket.handshake.address;
  const namespace = socket.nsp.name;

  // Remove from IP tracking
  if (ipConnections.has(clientIP)) {
    ipConnections.get(clientIP)!.delete(socket.id);
    
    // Clean up empty entries
    if (ipConnections.get(clientIP)!.size === 0) {
      ipConnections.delete(clientIP);
    }
  }

  // Remove from namespace tracking
  if (namespaceConnections.has(namespace)) {
    const nsState = namespaceConnections.get(namespace)!;
    nsState.sockets.delete(socket.id);
    nsState.socketCount = Math.max(0, nsState.socketCount - 1);
    
    // Clean up empty entries
    if (nsState.socketCount === 0) {
      namespaceConnections.delete(namespace);
    }
  }
};

/**
 * Get connection count for an IP
 */
export const getIPConnectionCount = (clientIP: string): number => {
  return ipConnections.get(clientIP)?.size || 0;
};

/**
 * Get connection count for a namespace
 */
export const getNamespaceConnectionCount = (namespace: string): number => {
  return namespaceConnections.get(namespace)?.socketCount || 0;
};

/**
 * Get all connection stats
 */
export const getConnectionStats = () => {
  const stats: any = {
    totalIPsConnected: ipConnections.size,
    namespaces: {}
  };

  for (const [namespace, state] of namespaceConnections) {
    stats.namespaces[namespace] = {
      totalConnections: state.socketCount,
      activeSocketCount: state.sockets.size
    };
  }

  return stats;
};

/**
 * Kick all connections from an IP (e.g., for abuse)
 */
export const disconnectIP = (socket: any, clientIP: string): void => {
  const sockets = ipConnections.get(clientIP);
  if (!sockets) return;

  for (const socketId of sockets) {
    const targetSocket = socket.nsp.sockets.get(socketId);
    if (targetSocket) {
      targetSocket.disconnect(true);
    }
  }

  ipConnections.delete(clientIP);
};

/**
 * Kick all connections from a namespace
 */
export const disconnectNamespace = (namespace: string, reason: string = "Server reset"): void => {
  if (!namespaceConnections.has(namespace)) return;

  const nsState = namespaceConnections.get(namespace)!;
  
  for (const socketId of nsState.sockets) {
    // Note: This requires access to the actual socket instance
    // Best called from within the namespace connection handler
  }

  namespaceConnections.delete(namespace);
};

/**
 * Middleware for Socket.IO namespace
 */
export const createConnectionLimitMiddleware = (
  config: ConnectionLimitConfig = DEFAULT_CONFIG
) => {
  return (socket: Socket, next: (err?: Error) => void) => {
    const { allowed, reason } = canConnect(socket, config);

    if (!allowed) {
      console.warn(`Connection rejected: ${reason}`);
      return next(new Error(reason || "Connection limit exceeded"));
    }

    // Register the connection
    registerConnection(socket);

    // Clean up on disconnect
    socket.on("disconnect", () => {
      unregisterConnection(socket);
    });

    next();
  };
};

/**
 * Get detailed connection info for debugging
 */
export const getDetailedConnectionStats = () => {
  const stats: any = {
    ips: {},
    namespaces: {}
  };

  for (const [ip, sockets] of ipConnections) {
    stats.ips[ip] = Array.from(sockets);
  }

  for (const [ns, state] of namespaceConnections) {
    stats.namespaces[ns] = {
      count: state.socketCount,
      sockets: Array.from(state.sockets)
    };
  }

  return stats;
};

import { Socket } from "socket.io";

interface RateLimitConfig {
  rate: number;           // events per second
  burst: number;          // max burst size
  window: number;         // time window in ms
}

interface RateLimitState {
  count: number;
  tokens: number;
  lastReset: number;
  burstUsed: number;
}

interface SocketRateLimitState extends RateLimitState {
  ipData?: IPRateLimitState;
  branchData?: BranchRateLimitState;
}

interface IPRateLimitState {
  count: number;
  tokens: number;
  lastReset: number;
}

interface BranchRateLimitState {
  count: number;
  tokens: number;
  lastReset: number;
}

// ===== GLOBAL STATE =====
const socketLimits = new Map<string, SocketRateLimitState>();
const ipLimits = new Map<string, IPRateLimitState>();
const branchLimits = new Map<string, BranchRateLimitState>();

const DEFAULT_CONFIG: RateLimitConfig = {
  rate: 20,               // 20 events/sec default
  burst: 40,              // burst up to 40
  window: 1000            // 1 second window
};

/**
 * Initialize rate limit state for a socket
 */
export const initSocketRateLimit = (
  socket: Socket,
  config: RateLimitConfig = DEFAULT_CONFIG
): SocketRateLimitState => {
  const clientIP = socket.handshake.address;
  
  const state: SocketRateLimitState = {
    count: 0,
    tokens: config.rate,
    lastReset: Date.now(),
    burstUsed: 0
  };

  // IP-based state
  if (!ipLimits.has(clientIP)) {
    ipLimits.set(clientIP, {
      count: 0,
      tokens: config.rate * 2,
      lastReset: Date.now()
    });
  }
  state.ipData = ipLimits.get(clientIP);

  // Branch-based state (if branch available)
  if (socket.data?.branchId) {
    const branchId = socket.data.branchId;
    if (!branchLimits.has(branchId)) {
      branchLimits.set(branchId, {
        count: 0,
        tokens: config.rate * 10,
        lastReset: Date.now()
      });
    }
    state.branchData = branchLimits.get(branchId);
  }

  socketLimits.set(socket.id, state);
  return state;
};

/**
 * Check if an event is allowed by rate limiting
 * Returns { allowed: boolean; reason?: string }
 */
export const checkRateLimit = (
  socket: Socket,
  config: RateLimitConfig = DEFAULT_CONFIG
): { allowed: boolean; reason?: string } => {
  const now = Date.now();
  
  // Get or init socket state
  let state = socketLimits.get(socket.id);
  if (!state) {
    state = initSocketRateLimit(socket, config);
  }

  // ===== SOCKET-LEVEL RATE LIMITING =====
  const timeSinceReset = now - state.lastReset;
  
  if (timeSinceReset >= config.window) {
    // Reset tokens
    state.tokens = config.rate;
    state.count = 0;
    state.burstUsed = 0;
    state.lastReset = now;
  }

  if (state.tokens > 0) {
    state.tokens--;
    state.count++;
    return { allowed: true };
  }

  // Use burst allowance
  if (state.burstUsed < config.burst) {
    state.burstUsed++;
    state.count++;
    return { allowed: true };
  }

  // Check IP-level rate limiting
  if (state.ipData) {
    const ipTimeSinceReset = now - state.ipData.lastReset;
    
    if (ipTimeSinceReset >= config.window) {
      state.ipData.tokens = config.rate * 2;
      state.ipData.count = 0;
      state.ipData.lastReset = now;
    }

    if (state.ipData.tokens > 0) {
      state.ipData.tokens--;
      state.ipData.count++;
      return { allowed: true };
    }
  }

  // Check branch-level rate limiting
  if (state.branchData && socket.data?.branchId) {
    const branchTimeSinceReset = now - state.branchData.lastReset;
    
    if (branchTimeSinceReset >= config.window) {
      state.branchData.tokens = config.rate * 10;
      state.branchData.count = 0;
      state.branchData.lastReset = now;
    }

    if (state.branchData.tokens > 0) {
      state.branchData.tokens--;
      state.branchData.count++;
      return { allowed: true };
    }
  }

  return { allowed: false, reason: "Rate limit exceeded" };
};

/**
 * Clean up rate limit state when socket disconnects
 */
export const cleanupSocketRateLimit = (socket: Socket): void => {
  socketLimits.delete(socket.id);
};

/**
 * Get rate limit stats for a socket
 */
export const getRateLimitStats = (socket: Socket) => {
  const state = socketLimits.get(socket.id);
  if (!state) return null;

  return {
    socketId: socket.id,
    eventCount: state.count,
    tokens: state.tokens,
    burstUsed: state.burstUsed,
    ipCount: state.ipData?.count || 0,
    branchCount: state.branchData?.count || 0
  };
};

/**
 * Middleware for Socket.IO namespace
 */
export const createRateLimitMiddleware = (config: RateLimitConfig = DEFAULT_CONFIG) => {
  return (socket: Socket, next: (err?: Error) => void) => {
    // Initialize rate limit for this socket
    initSocketRateLimit(socket, config);
    next();
  };
};

/**
 * Event listener wrapper that enforces rate limiting
 */
export const withRateLimit = (
  socket: Socket,
  event: string,
  handler: (data: any) => void,
  config: RateLimitConfig = DEFAULT_CONFIG
) => {
  socket.on(event, (data) => {
    const { allowed, reason } = checkRateLimit(socket, config);
    
    if (!allowed) {
      console.warn(`Rate limit exceeded for event "${event}" on socket ${socket.id}: ${reason}`);
      return;
    }

    handler(data);
  });
};

/**
 * Cleanup all rate limit data for an IP when needed
 */
export const cleanupIPRateLimit = (clientIP: string): void => {
  ipLimits.delete(clientIP);
};

/**
 * Cleanup all rate limit data for a branch
 */
export const cleanupBranchRateLimit = (branchId: string): void => {
  branchLimits.delete(branchId);
};

/**
 * Get all rate limit stats
 */
export const getAllRateLimitStats = () => {
  return {
    activeSocketLimits: socketLimits.size,
    activeIPLimits: ipLimits.size,
    activeBranchLimits: branchLimits.size
  };
};

import { Socket, Namespace } from "socket.io";

interface RoomState {
  name: string;
  type: string;           // customer, courier, kds, admin
  branchId?: string;
  createdAt: number;
  socketCount: number;
  sockets: Set<string>;
  lastActivity: number;
}

// ===== GLOBAL STATE =====
const rooms = new Map<string, RoomState>();
const socketToRooms = new Map<string, Set<string>>();  // socket ID -> room names
const branchRooms = new Map<string, Set<string>>();    // branch ID -> room names

const ROOM_CLEANUP_TIMEOUT = 60000; // 1 minute of inactivity
const ROOM_CLEANUP_CHECK_INTERVAL = 30000; // Check every 30 seconds

/**
 * Get or create a room (lazy creation)
 */
export const getOrCreateRoom = (
  namespace: Namespace,
  roomName: string,
  branchId?: string
): RoomState => {
  if (!rooms.has(roomName)) {
    rooms.set(roomName, {
      name: roomName,
      type: extractRoomType(roomName),
      branchId,
      createdAt: Date.now(),
      socketCount: 0,
      sockets: new Set(),
      lastActivity: Date.now()
    });
  }

  return rooms.get(roomName)!;
};

/**
 * Join a socket to a room with lazy creation
 */
export const joinRoom = (
  socket: Socket,
  roomName: string,
  branchId?: string
): RoomState => {
  const room = getOrCreateRoom(socket.nsp, roomName, branchId);
  
  socket.join(roomName);
  room.sockets.add(socket.id);
  room.socketCount++;
  room.lastActivity = Date.now();

  // Track socket -> rooms mapping
  if (!socketToRooms.has(socket.id)) {
    socketToRooms.set(socket.id, new Set());
  }
  socketToRooms.get(socket.id)!.add(roomName);

  // Track branch -> rooms mapping
  if (branchId) {
    if (!branchRooms.has(branchId)) {
      branchRooms.set(branchId, new Set());
    }
    branchRooms.get(branchId)!.add(roomName);
  }

  return room;
};

/**
 * Leave a room and clean up if empty
 */
export const leaveRoom = (socket: Socket, roomName: string): boolean => {
  const room = rooms.get(roomName);
  if (!room) return false;

  socket.leave(roomName);
  room.sockets.delete(socket.id);
  room.socketCount = Math.max(0, room.socketCount - 1);
  room.lastActivity = Date.now();

  // Clean up socket -> rooms mapping
  if (socketToRooms.has(socket.id)) {
    socketToRooms.get(socket.id)!.delete(roomName);
  }

  // Delete empty room
  if (room.socketCount === 0) {
    rooms.delete(roomName);
    
    // Clean up branch -> rooms mapping
    if (room.branchId && branchRooms.has(room.branchId)) {
      branchRooms.get(room.branchId)!.delete(roomName);
      
      if (branchRooms.get(room.branchId)!.size === 0) {
        branchRooms.delete(room.branchId);
      }
    }
    
    return true;
  }

  return false;
};

/**
 * Clean up all rooms when socket disconnects
 */
export const cleanupSocketRooms = (socket: Socket): void => {
  const socketRooms = socketToRooms.get(socket.id);
  if (!socketRooms) return;

  for (const roomName of socketRooms) {
    leaveRoom(socket, roomName);
  }

  socketToRooms.delete(socket.id);
};

/**
 * Get rooms for a socket
 */
export const getSocketRooms = (socket: Socket): RoomState[] => {
  const socketRooms = socketToRooms.get(socket.id) || new Set();
  return Array.from(socketRooms)
    .map(roomName => rooms.get(roomName))
    .filter((room): room is RoomState => room !== undefined);
};

/**
 * Get rooms for a branch
 */
export const getBranchRooms = (branchId: string): RoomState[] => {
  const branchRoomNames = branchRooms.get(branchId) || new Set();
  return Array.from(branchRoomNames)
    .map(roomName => rooms.get(roomName))
    .filter((room): room is RoomState => room !== undefined);
};

/**
 * Get all active rooms
 */
export const getAllRooms = (): RoomState[] => {
  return Array.from(rooms.values());
};

/**
 * Get room stats
 */
export const getRoomStats = (roomName: string): RoomState | null => {
  return rooms.get(roomName) || null;
};

/**
 * Get branch-aware metrics
 */
export const getBranchMetrics = (branchId: string) => {
  const branchRoomList = getBranchRooms(branchId);
  
  return {
    branchId,
    totalRooms: branchRoomList.length,
    totalConnections: branchRoomList.reduce((sum, room) => sum + room.socketCount, 0),
    rooms: branchRoomList.map(room => ({
      name: room.name,
      type: room.type,
      sockets: room.socketCount,
      lastActivity: room.lastActivity
    }))
  };
};

/**
 * Get global room metrics
 */
export const getGlobalMetrics = () => {
  const allRooms = getAllRooms();
  
  return {
    totalRooms: allRooms.length,
    totalConnections: allRooms.reduce((sum, room) => sum + room.socketCount, 0),
    totalBranches: branchRooms.size,
    roomsByType: groupBy(
      allRooms,
      room => room.type
    )
  };
};

export const updateSocketRoomCount = (roomName: string): void => {
  updateRoomActivity(roomName);
};

/**
 * Start automatic cleanup of inactive rooms
 */
export const startRoomCleanup = (namespace: Namespace): NodeJS.Timer => {
  return setInterval(async () => {
    const now = Date.now();
    const toDelete: string[] = [];

    for (const [roomName, room] of rooms) {
      // Delete empty rooms
      if (room.socketCount === 0) {
        toDelete.push(roomName);
      }
      // Delete inactive rooms after timeout
      else if (now - room.lastActivity > ROOM_CLEANUP_TIMEOUT) {
        // Use structured logging for cleanup notices
        // eslint-disable-next-line no-console
        // (leave message for visibility if logger isn't configured yet)
        // Replace with pino logger
        // Import logger dynamically to avoid circular deps
        try {
          const logger = (await import("../../logger.ts")).default;
          logger.info({ roomName, idleSeconds: (now - room.lastActivity) / 1000 }, "Auto-cleanup: inactive room");
        } catch (e) {
          // Fallback to console if logger import fails
          // eslint-disable-next-line no-console
          console.log(`Auto-cleanup: room "${roomName}" inactive for ${(now - room.lastActivity) / 1000}s`);
        }
        toDelete.push(roomName);
      }
    }

    for (const roomName of toDelete) {
      rooms.delete(roomName);
    }
  }, ROOM_CLEANUP_CHECK_INTERVAL);
};

/**
 * Manual cleanup of a specific room
 */
export const forceCleanupRoom = (roomName: string, namespace: Namespace): void => {
  const room = rooms.get(roomName);
  if (!room) return;

  // Disconnect all sockets in room
  namespace.to(roomName).disconnectSockets();
  rooms.delete(roomName);

  // Clean up mappings
  for (const socketId of room.sockets) {
    if (socketToRooms.has(socketId)) {
      socketToRooms.get(socketId)!.delete(roomName);
    }
  }

  if (room.branchId && branchRooms.has(room.branchId)) {
    branchRooms.get(room.branchId)!.delete(roomName);
  }
};

/**
 * Update room activity timestamp
 */
export const updateRoomActivity = (roomName: string): void => {
  const room = rooms.get(roomName);
  if (room) {
    room.lastActivity = Date.now();
  }
};

/**
 * Extract room type from room name
 */
function extractRoomType(roomName: string): string {
  if (roomName.startsWith("customer_")) return "customer";
  if (roomName.startsWith("courier_")) return "courier";
  if (roomName.startsWith("kds_")) return "kds";
  if (roomName.startsWith("admin_")) return "admin";
  if (roomName.startsWith("order_")) return "order";
  if (roomName.startsWith("branch_")) return "branch";
  return "unknown";
}

/**
 * Group array by property
 */
function groupBy<T>(arr: T[], keyFn: (item: T) => string): Record<string, T[]> {
  return arr.reduce((acc, item) => {
    const key = keyFn(item);
    if (!acc[key]) acc[key] = [];
    acc[key].push(item);
    return acc;
  }, {} as Record<string, T[]>);
}

import { Socket } from "socket.io";

interface ThrottleState {
  lastEmitTime: number;
  pendingData?: any;
  timeout?: NodeJS.Timeout;
}

// ===== GLOBAL STATE =====
const throttleStates = new Map<string, Map<string, ThrottleState>>();

interface ThrottleConfig {
  interval: number;  // ms between events
  trailing?: boolean; // emit last pending event after throttle expires
}

/**
 * Initialize throttle state for a socket and event
 */
const initThrottleState = (socketId: string, event: string): ThrottleState => {
  if (!throttleStates.has(socketId)) {
    throttleStates.set(socketId, new Map());
  }

  const socketEvents = throttleStates.get(socketId)!;
  
  if (!socketEvents.has(event)) {
    socketEvents.set(event, { lastEmitTime: 0 });
  }

  return socketEvents.get(event)!;
};

/**
 * Throttle an emit operation
 * Returns { allowed: boolean; emit?: () => void }
 */
export const throttleEmit = (
  socket: Socket,
  event: string,
  data: any,
  config: ThrottleConfig
): { allowed: boolean; queued?: boolean } => {
  const now = Date.now();
  const state = initThrottleState(socket.id, event);
  const timeSinceLastEmit = now - state.lastEmitTime;

  if (timeSinceLastEmit >= config.interval) {
    // Allow emit immediately
    state.lastEmitTime = now;
    state.pendingData = undefined;

    // Clear any pending timeout
    if (state.timeout) {
      clearTimeout(state.timeout);
      state.timeout = undefined;
    }

    return { allowed: true };
  }

  // Store pending data
  state.pendingData = data;

  // Schedule trailing emit if enabled
  if (config.trailing && !state.timeout) {
    const remainingTime = config.interval - timeSinceLastEmit;
    
    state.timeout = setTimeout(() => {
      if (state.pendingData) {
        state.lastEmitTime = Date.now();
        state.pendingData = undefined;
        state.timeout = undefined;
      }
    }, remainingTime);
  }

  return { allowed: false, queued: true };
};

/**
 * Get pending data for a throttled event (for manual trailing)
 */
export const getPendingData = (socket: Socket, event: string): any => {
  const state = initThrottleState(socket.id, event);
  return state.pendingData;
};

/**
 * Force emit pending data and reset throttle
 */
export const flushPending = (socket: Socket, event: string): any => {
  const state = initThrottleState(socket.id, event);
  
  if (state.timeout) {
    clearTimeout(state.timeout);
    state.timeout = undefined;
  }

  const pending = state.pendingData;
  state.pendingData = undefined;
  state.lastEmitTime = Date.now();

  return pending;
};

/**
 * Clean up throttle state when socket disconnects
 */
export const cleanupSocketThrottle = (socket: Socket): void => {
  if (!throttleStates.has(socket.id)) return;

  const socketEvents = throttleStates.get(socket.id)!;
  
  // Clear all pending timeouts
  for (const state of socketEvents.values()) {
    if (state.timeout) {
      clearTimeout(state.timeout);
    }
  }

  throttleStates.delete(socket.id);
};

/**
 * Get throttle stats for a socket
 */
export const getThrottleStats = (socket: Socket) => {
  if (!throttleStates.has(socket.id)) return null;

  const socketEvents = throttleStates.get(socket.id)!;
  const stats: any = {};

  for (const [event, state] of socketEvents) {
    stats[event] = {
      lastEmitTime: state.lastEmitTime,
      hasPending: !!state.pendingData,
      hasPendingTimeout: !!state.timeout
    };
  }

  return stats;
};

/**
 * Decorator-like function for throttled socket event handlers
 */
export const withThrottle = (
  socket: Socket,
  event: string,
  handler: (data: any) => void,
  config: ThrottleConfig
) => {
  const effectiveConfig: ThrottleConfig = {
    interval: config.interval,
    trailing: config.trailing !== false  // Default to trailing enabled
  };

  socket.on(event, (data) => {
    const { allowed } = throttleEmit(socket, event, data, effectiveConfig);

    if (allowed) {
      handler(data);
    }
  });
};

/**
 * Create a throttled emit wrapper
 */
export const createThrottledEmitter = (
  socket: Socket,
  config: ThrottleConfig
) => {
  return (event: string, data: any) => {
    const { allowed } = throttleEmit(socket, event, data, config);
    return allowed;
  };
};

/**
 * Reset throttle state for a specific event
 */
export const resetEventThrottle = (socket: Socket, event: string): void => {
  if (!throttleStates.has(socket.id)) return;

  const socketEvents = throttleStates.get(socket.id)!;
  
  if (socketEvents.has(event)) {
    const state = socketEvents.get(event)!;
    if (state.timeout) {
      clearTimeout(state.timeout);
    }
    socketEvents.delete(event);
  }
};

/**
 * Get all throttle stats across all sockets
 */
export const getAllThrottleStats = () => {
  return {
    activeSockets: throttleStates.size,
    totalThrottledEvents: Array.from(throttleStates.values()).reduce(
      (sum, events) => sum + events.size,
      0
    )
  };
};

