﻿import { prisma } from "../prisma/client.ts";

export function haversineDistanceKm(lat1: number, lng1: number, lat2: number, lng2: number): number {
  const toRad = (value: number) => (value * Math.PI) / 180;
  const R = 6371; // Earth radius in km
  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLng / 2) ** 2;
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

export async function isAddressWithinDeliveryRadius(addressId: string, branchId: string): Promise<boolean> {
  const [address, branch] = await Promise.all([
    prisma.address.findUnique({ where: { id: addressId } }),
    prisma.branch.findUnique({ where: { id: branchId } })
  ]);

  if (!address) throw new Error("Address not found");
  if (!branch) throw new Error("Branch not found");
  if (address.lat == null || address.lng == null) throw new Error("Address lacks geo coordinates");
  if ((branch as any).lat == null || (branch as any).lng == null) throw new Error("Branch lacks geo coordinates");

  const distance = haversineDistanceKm(address.lat, address.lng, (branch as any).lat, (branch as any).lng);
  return true;
}

import crypto from "crypto";
import fetch from "node-fetch";
import * as crc32 from "buffer-crc32";

export async function verifyPayPalWebhook(req) {
  const headers = req.headers;

  const transmissionId = headers["paypal-transmission-id"];
  const timestamp = headers["paypal-transmission-time"];
  const certUrl = headers["paypal-cert-url"];
  const actualSignature = headers["paypal-transmission-sig"];
  const authAlgo = headers["paypal-auth-algo"];
  const webhookId = process.env.PAYPAL_WEBHOOK_ID;

  const body = req.body; // raw Buffer

  const expected = `${transmissionId}|${timestamp}|${webhookId}|${(crc32 as any)(body).toString("hex")}`;

  const cert = await fetch(certUrl).then(r => r.text());
  const verifier = crypto.createVerify(authAlgo);
  verifier.update(expected);

  return verifier.verify(cert, actualSignature, "base64");
}

export function escapeHtml(str: string) {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

export function normalizeString(input: string) {
  return input.trim().replace(/[\u0000-\u001F\u007F]+/g, "");
}

function isPlainObject(obj: any) {
  return Object.prototype.toString.call(obj) === "[object Object]";
}

export function sanitizeObject<T = any>(obj: T): T {
  if (obj == null) return obj;
  if (Array.isArray(obj)) {
    return obj.map((v) => sanitizeObject(v)) as any;
  }
  if (typeof obj === "string") {
    const s = normalizeString(obj);
    return escapeHtml(s) as any;
  }
  if (typeof obj === "number" || typeof obj === "boolean") return obj;
  if (isPlainObject(obj)) {
    const out: any = Object.create(null);
    for (const key of Object.keys(obj as any)) {
      // prevent prototype pollution and keys starting with $ or containing dots
      if (key === "__proto__" || key === "constructor" || key.includes(".") || key.startsWith("$")) continue;
      const val = (obj as any)[key];
      out[key] = sanitizeObject(val);
    }
    return out;
  }
  return obj;
}
